import{r}from"./request-Cz_k180i.js";const u={list(e){return r.get("/requirement/list",{params:e})},get(e){return r.get(`/requirement/${e}`)},create(e){return r.post("/requirement",e)},approve(e,t){return r.put(`/requirement/${e}/approve`,null,{params:{comment:t}})},reject(e,t){return r.put(`/requirement/${e}/reject`,null,{params:{comment:t}})},pending(){return r.get("/requirement/pending")},checkDuplicate(e){return r.post("/requirement/check-duplicate",e)}};export{u as r};
